2724 void Verifier::visitConstantExprsRecursively(const Constant *EntryC) {
2725   if (EntryC->getNumOperands() == 0)
2726     return;
2727 
2728   if (!ConstantExprVisited.insert(EntryC).second)
2729     return;
2730 
2731   SmallVector<const Constant *, 16> Stack;
2732   Stack.push_back(EntryC);
2733 
2734   while (!Stack.empty()) {
2735     const Constant *C = Stack.pop_back_val();
2736 
2737     // Check this constant expression.
2738     if (const auto *CE = dyn_cast<ConstantExpr>(C))
2739       visitConstantExpr(CE);
2740 
2741     if (const auto *CPA = dyn_cast<ConstantPtrAuth>(C))
2742       visitConstantPtrAuth(CPA);
2743 
2744     if (const auto *GV = dyn_cast<GlobalValue>(C)) {
2745       // Global Values get visited separately, but we do need to make sure
2746       // that the global value is in the correct module
2747       Check(GV->getParent() == &M, "Referencing global in another module!",
2748             EntryC, &M, GV, GV->getParent());
2749       continue;
2750     }
2751 
2752     // Visit all sub-expressions.
2753     for (const Use &U : C->operands()) {
2754       const auto *OpC = dyn_cast<Constant>(U);
2755       if (!OpC)
2756         continue;
2757       if (!ConstantExprVisited.insert(OpC).second)
2758         continue;
2759       Stack.push_back(OpC);
2760     }
2761   }
2762 }
