2767                                 CE->getType()),
2768           "Invalid bitcast", CE);
2769   else if (CE->getOpcode() == Instruction::PtrToAddr)
2770     checkPtrToAddr(CE->getOperand(0)->getType(), CE->getType(), *CE);
2771 }
