2109   // Check if there is a dominating condition, that implies that the value
2110   // being stored in a ptr is already present in the ptr.
2111   bool dominatingConditionImpliesValue(MemoryDef *Def) {
2112     auto *StoreI = cast<StoreInst>(Def->getMemoryInst());
2113     BasicBlock *StoreBB = StoreI->getParent();
2114     Value *StorePtr = StoreI->getPointerOperand();
2115     Value *StoreVal = StoreI->getValueOperand();
2116 
2117     DomTreeNode *IDom = DT.getNode(StoreBB)->getIDom();
2118     if (!IDom)
2119       return false;
2120 
2121     auto *BI = dyn_cast<BranchInst>(IDom->getBlock()->getTerminator());
2122     if (!BI || !BI->isConditional())
2123       return false;
2124 
2125     // In case both blocks are the same, it is not possible to determine
2126     // if optimization is possible. (We would not want to optimize a store
2127     // in the FalseBB if condition is true and vice versa.)
2128     if (BI->getSuccessor(0) == BI->getSuccessor(1))
2129       return false;
2130 
2131     Instruction *ICmpL;
2132     CmpPredicate Pred;
2133     if (!match(BI->getCondition(),
2134                m_c_ICmp(Pred,
2135                         m_CombineAnd(m_Load(m_Specific(StorePtr)),
2136                                      m_Instruction(ICmpL)),
2137                         m_Specific(StoreVal))) ||
2138         !ICmpInst::isEquality(Pred))
2139       return false;
2140 
2141     // In case the else blocks also branches to the if block or the other way
2142     // around it is not possible to determine if the optimization is possible.
2143     if (Pred == ICmpInst::ICMP_EQ &&
2144         !DT.dominates(BasicBlockEdge(BI->getParent(), BI->getSuccessor(0)),
2145                       StoreBB))
2146       return false;
2147 
2148     if (Pred == ICmpInst::ICMP_NE &&
2149         !DT.dominates(BasicBlockEdge(BI->getParent(), BI->getSuccessor(1)),
2150                       StoreBB))
2151       return false;
2152 
2153     MemoryAccess *LoadAcc = MSSA.getMemoryAccess(ICmpL);
2154     MemoryAccess *ClobAcc =
2155         MSSA.getSkipSelfWalker()->getClobberingMemoryAccess(Def, BatchAA);
2156 
2157     return MSSA.dominates(ClobAcc, LoadAcc);
