2160   /// \returns true if \p Def is a no-op store, either because it
2161   /// directly stores back a loaded value or stores zero to a calloced object.
2162   bool storeIsNoop(MemoryDef *Def, const Value *DefUO) {
2163     Instruction *DefI = Def->getMemoryInst();
2164     StoreInst *Store = dyn_cast<StoreInst>(DefI);
2165     MemSetInst *MemSet = dyn_cast<MemSetInst>(DefI);
2166     Constant *StoredConstant = nullptr;
2167     if (Store)
2168       StoredConstant = dyn_cast<Constant>(Store->getOperand(0));
2169     else if (MemSet)
2170       StoredConstant = dyn_cast<Constant>(MemSet->getValue());
2171     else
2172       return false;
2173 
2174     if (!isRemovable(DefI))
2175       return false;
2176 
2177     if (StoredConstant) {
2178       Constant *InitC =
2179           getInitialValueOfAllocation(DefUO, &TLI, StoredConstant->getType());
2180       // If the clobbering access is LiveOnEntry, no instructions between them
2181       // can modify the memory location.
2182       if (InitC && InitC == StoredConstant)
2183         return MSSA.isLiveOnEntryDef(
2184             MSSA.getSkipSelfWalker()->getClobberingMemoryAccess(Def, BatchAA));
2185     }
2186 
2187     if (!Store)
2188       return false;
2189 
2190     if (dominatingConditionImpliesValue(Def))
2191       return true;
2192 
2193     if (auto *LoadI = dyn_cast<LoadInst>(Store->getOperand(0))) {
2194       if (LoadI->getPointerOperand() == Store->getOperand(1)) {
2195         // Get the defining access for the load.
2196         auto *LoadAccess = MSSA.getMemoryAccess(LoadI)->getDefiningAccess();
2197         // Fast path: the defining accesses are the same.
2198         if (LoadAccess == Def->getDefiningAccess())
2199           return true;
2200 
2201         // Look through phi accesses. Recursively scan all phi accesses by
2202         // adding them to a worklist. Bail when we run into a memory def that
2203         // does not match LoadAccess.
2204         SetVector<MemoryAccess *> ToCheck;
2205         MemoryAccess *Current =
2206             MSSA.getWalker()->getClobberingMemoryAccess(Def, BatchAA);
2207         // We don't want to bail when we run into the store memory def. But,
2208         // the phi access may point to it. So, pretend like we've already
2209         // checked it.
2210         ToCheck.insert(Def);
2211         ToCheck.insert(Current);
2212         // Start at current (1) to simulate already having checked Def.
2213         for (unsigned I = 1; I < ToCheck.size(); ++I) {
2214           Current = ToCheck[I];
2215           if (auto PhiAccess = dyn_cast<MemoryPhi>(Current)) {
2216             // Check all the operands.
2217             for (auto &Use : PhiAccess->incoming_values())
2218               ToCheck.insert(cast<MemoryAccess>(&Use));
2219             continue;
2220           }
2221 
2222           // If we found a memory def, bail. This happens when we have an
2223           // unrelated write in between an otherwise noop store.
2224           assert(isa<MemoryDef>(Current) &&
2225                  "Only MemoryDefs should reach here.");
2226           // TODO: Skip no alias MemoryDefs that have no aliasing reads.
2227           // We are searching for the definition of the store's destination.
2228           // So, if that is the same definition as the load, then this is a
2229           // noop. Otherwise, fail.
2230           if (LoadAccess != Current)
2231             return false;
2232         }
2233         return true;
2234       }
2235     }
2236 
2237     return false;
2238   }
