2293           if (auto *SI = dyn_cast<StoreInst>(DefInst)) {
2294             // MemSetInst must have a write location.
2295             auto UpperLoc = getLocForWrite(UpperInst);
2296             if (!UpperLoc)
2297               return false;
2298             int64_t InstWriteOffset = 0;
2299             int64_t DepWriteOffset = 0;
2300             auto OR = isOverwrite(UpperInst, DefInst, *UpperLoc, *MaybeDefLoc,
2301                                   InstWriteOffset, DepWriteOffset);
2302             Value *StoredByte = isBytewiseValue(SI->getValueOperand(), DL);
2303             return StoredByte && StoredByte == MemSetI->getOperand(1) &&
